import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecureFileReadExample {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User input with malicious intent

        // Validate and sanitize user input to prevent path traversal
        String sanitizedInput = sanitizeInput(userInput);

        String baseDirectory = "files/";
        File file = new File(baseDirectory, sanitizedInput);

        try (FileInputStream fis = new FileInputStream(file)) {
            int data;
            while ((data = fis.read()) != -1) {
                System.out.print((char) data);
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }

    private static String sanitizeInput(String userInput) {
        // Use Java's Paths API to normalize and resolve the file path
        return Paths.get(userInput).normalize().toString();
    }
}

